function getSafeDashboardTheme(config) {
  const userIsActive = config && config.user && config.user.isActive;
  if (!userIsActive) {
    return 'guest-theme';
  }
  const configuredTheme = config.theme ?? 'default-dark';
  return configuredTheme;
}

const nullConfig = null;
const userConfig = { user: { isActive: true }, theme: 'sunset-neon' };
const minimalConfig = { user: { isActive: true } };

console.log(getSafeDashboardTheme(nullConfig));
console.log(getSafeDashboardTheme(userConfig));
console.log(getSafeDashboardTheme(minimalConfig));

