function classifyScore(score) {
  switch (true) {
    case (score < 0 || score > 100):
      return 'Invalid Score';
    case (score >= 90):
      return 'Excellent';
    case (score >= 70):
      return 'Passing';
    default:
      return 'Requires Improvement';
  }
}

console.log(classifyScore(-10));
console.log(classifyScore(95));
console.log(classifyScore(82));
console.log(classifyScore(55));

