function meetsRules(record, rules) {
  return rules.every(rule => {
    const targetVal = record[rule.field];
    if (rule.operator === '===') {
      return targetVal === rule.value;
    }
    if (rule.operator === '>') {
      return targetVal > rule.value;
    }
    return false;
  });
}

